<template>
  <CCard class="mb-3">
    <CCardBody>
      <CInput v-model="url" label="API URL" />

      <div class="mt-2">
        <CButton color="primary" @click="preview"> Preview Data </CButton>

        <CButton
          class="mx-2"
          color="success"
          :disabled="!previewData.length"
          @click="apply"
        >
          Apply to Document
        </CButton>
      </div>

      <div v-if="previewData.length" class="mt-3">
        <p><strong>Total records:</strong> {{ previewData.length }}</p>

        <CDataTable
          :items="previewData.slice(0, 5)"
          :fields="Object.keys(previewData[0])"
          small
        />
      </div>
    </CCardBody>
  </CCard>
</template>

<script>
import { CCard, CCardBody, CInput, CButton } from "@coreui/vue";

export default {
  components: { CCard, CCardBody, CInput, CButton },

  data() {
    return {
      url: "",
      previewData: [],
    };
  },

  methods: {
    async preview() {
      const res = await fetch(this.url);
      this.previewData = await res.json();
    },

    apply() {
      this.$emit("loaded", this.previewData);
    },
  },
};
</script>
